40	/// Banner string emitted as the first line of normal command runs
41	/// and shown at the top of subcommand `--help` output. Built from
42	/// `Cargo.toml`'s name + version at compile time so it stays in
43	/// sync with the bumped version.
44	const BANNER: &str = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION"));
45	
46	/// Top-level about line — name, version, and the project tagline
47	/// on a single line. Used as the top-level `about` so `vc-x1 -h`
48	/// reads as one banner-plus-tagline header instead of two stacked
49	/// lines.
50	const TOP_ABOUT: &str = concat!(
51	    env!("CARGO_PKG_NAME"),
52	    " ",
53	    env!("CARGO_PKG_VERSION"),
54	    " - jj workspace tooling"
55	);
