57	/// Build the clap command tree with `BANNER` set as `before_help`
58	/// on every subcommand (transitively). Top-level skips `before_help`
59	/// because its own `about` already carries the name+version+tagline.
60	/// Walks via `mut_subcommand` so individual subcommand
61	/// `#[command(long_about = ...)]` blocks don't have to repeat the
62	/// banner text.
63	fn cli_with_banner() -> clap::Command {
64	    fn add_to_subs(mut cmd: clap::Command) -> clap::Command {
65	        let names: Vec<String> = cmd
66	            .get_subcommands()
67	            .map(|c| c.get_name().to_string())
68	            .collect();
69	        for name in names {
70	            cmd = cmd.mut_subcommand(name, add_with_banner);
71	        }
72	        cmd
73	    }
74	    fn add_with_banner(mut cmd: clap::Command) -> clap::Command {
75	        cmd = cmd.before_help(BANNER);
76	        let names: Vec<String> = cmd
77	            .get_subcommands()
78	            .map(|c| c.get_name().to_string())
79	            .collect();
80	        for name in names {
81	            cmd = cmd.mut_subcommand(name, add_with_banner);
82	        }
83	        cmd
84	    }
85	    add_to_subs(Cli::command())
86	}
