243	/// Permanent sanity check for the `main`-bookmark tracking state
244	/// in both repos of the dual-repo workspace. Emits one line on
245	/// entry and one on exit of every command. If entry and exit
246	/// differ, the executing command is the culprit; if entry differs
247	/// from the previous command's exit, something *between*
248	/// invocations broke it. Originally added in 0.37.2 as a temporary
249	/// diagnostic; promoted to permanent in 0.37.4 after the user
250	/// reported "happens more than once".
251	///
252	/// Emits at `log::debug!` (since 0.52.0-1) — default runs stay
253	/// quiet, and the signal remains available under `-v` when
254	/// investigating. The detached `finalize --exec` child runs at
255	/// default verbosity so it stays silent without needing a special
256	/// gate at the call site.
257	///
258	/// Walks up from cwd to locate the workspace root (the directory
259	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
260	/// and `<root>/.claude`. Same labeling whether the user runs from
261	/// the app root, from `.claude`, or from any subdir.
262	pub fn bm_track(phase: &str, command_name: &str) {
263	    let header = format!("bm-track {phase} vc-x1 {command_name}");
264	    let root = match common::find_workspace_root() {
265	        Some(r) => r,
266	        None => {
267	            log::debug!("{header}: no-workspace");
268	            return;
269	        }
270	    };
271	    let repos: [(std::path::PathBuf, &str); 2] =
272	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
273	    let mut parts: Vec<String> = Vec::new();
274	    for (repo, label) in repos {
275	        if !repo.join(".jj").exists() {
276	            parts.push(format!("{label}(main)=no-jj"));
277	            continue;
278	        }
279	        match bm_track_one(&repo, "main", "origin") {
280	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
281	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
282	            Err(e) => parts.push(format!(
283	                "{label}(main)=err({})",
284	                e.lines().next().unwrap_or("")
285	            )),
286	        }
287	    }
288	    log::debug!("{header}: {}", parts.join(", "));
289	}
