291	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
292	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
293	/// an `@<remote>` line (in any form — `@origin:` when synced, or
294	/// `@origin (ahead by N commits):` / similar when divergent — both
295	/// still count as tracking). `Ok(false)` when no such line exists
296	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
297	/// subprocess failure.
298	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
299	    let repo_str = repo.to_string_lossy();
300	    let output = std::process::Command::new("jj")
301	        .args(["bookmark", "list", "--tracked", bookmark, "-R", &repo_str])
302	        .output()
303	        .map_err(|e| format!("spawn: {e}"))?;
304	    if !output.status.success() {
305	        return Err(String::from_utf8_lossy(&output.stderr).trim().to_string());
306	    }
307	    let stdout = String::from_utf8_lossy(&output.stdout);
308	    // Accept both the synced form (`@origin:`) and the decorated
309	    // divergent form (`@origin (ahead by N commits):`), which still
310	    // represents a tracking relationship.
311	    let colon = format!("@{remote}:");
312	    let paren = format!("@{remote} ");
313	    Ok(stdout.lines().any(|l| {
314	        let t = l.trim_start();
315	        t.starts_with(&colon) || t.starts_with(&paren)
316	    }))
317	}
