319	fn main() -> ExitCode {
320	    CompleteEnv::with_factory(cli_with_banner).complete();
321	    let matches = cli_with_banner().get_matches();
322	    let cli = match Cli::from_arg_matches(&matches) {
323	        Ok(cli) => cli,
324	        Err(e) => {
325	            e.exit();
326	        }
327	    };
328	
329	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
330	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
331	
332	    // `-V` / `--version`: emit the `vc-x1 X.Y.Z` banner as the
333	    // first line and continue. With no subcommand, the banner is
334	    // the whole invocation. Uniform `BANNER` (not the
335	    // `vc-x1-<sub>` form clap's `propagate_version` would print)
336	    // — the version is the binary's regardless of which
337	    // subcommand it routes to.
338	    if cli.version {
339	        log::info!("{BANNER}");
340	    }
341	
342	    let Some(cmd) = cli.command else {
343	        // No subcommand. If `-V` was set the banner has already
344	        // printed, so exit success; otherwise mirror clap's "a
345	        // subcommand is required" error by printing usage and
346	        // exiting non-zero.
347	        if cli.version {
348	            return ExitCode::SUCCESS;
349	        }
350	        let mut cmd = cli_with_banner();
351	        let _ = cmd.print_help();
352	        return ExitCode::FAILURE;
353	    };
354	
355	    // Surface any failure markers left by previous detached
356	    // `finalize --exec` children before running the next command.
357	    // Skip when this *is* the exec child — surfacing destroys the
358	    // markers, and the child's log isn't where the user looks for
359	    // them. This gate covers one race (detached child eating its
360	    // own prior markers); the broader surfacing model has more
361	    // gaps (stale-forever, concurrent double-print, mid-write torn
362	    // read, no notify-at-failure) tracked at
363	    // [../notes/todo.md#bugs] — see the
364	    // `finalize::surface_previous_failures is racy` entry.
365	    match &cmd {
366	        Commands::Finalize(args) => {
367	            if !args.exec {
368	                finalize::surface_previous_failures();
369	            }
370	        }
371	        _ => finalize::surface_previous_failures(),
372	    }
373	
374	    let ctx = match context::Context::load(cli.log) {
375	        Ok(c) => c,
376	        Err(e) => {
377	            error!("{e}");
378	            return ExitCode::FAILURE;
379	        }
380	    };
381	
382	    match cmd {
383	        Commands::Chid(args) => args.dispatch(&ctx),
384	        Commands::Desc(args) => args.dispatch(&ctx),
385	        Commands::List(args) => args.dispatch(&ctx),
386	        Commands::Show(args) => args.dispatch(&ctx),
387	        Commands::ValidateDesc(args) => args.dispatch(&ctx),
388	        Commands::FixDesc(args) => args.dispatch(&ctx),
389	        Commands::ValidateTodo(args) => args.dispatch(&ctx),
390	        Commands::FixTodo(args) => args.dispatch(&ctx),
391	        Commands::Clone(args) => args.dispatch(&ctx),
392	        Commands::Init(args) => args.dispatch(&ctx),
393	        Commands::Symlink(args) => args.dispatch(&ctx),
394	        Commands::Sync(args) => args.dispatch(&ctx),
395	        Commands::Finalize(args) => args.dispatch(&ctx),
396	        Commands::Push(args) => args.dispatch(&ctx),
397	    }
398	}
