594	/// Resolve the workspace's default `--scope`.
595	///
596	/// Reads `<workspace_root>/.vc-config.toml > [workspace] other-repo`:
597	///
598	/// - dual workspace (non-empty `other-repo`) → `Scope([Code, Bot])`
599	/// - single-repo workspace (missing / empty `other-repo`) →
600	///   `Scope([Code])`
601	/// - POR (no `workspace_root`) → `Scope([Code])` — `scope_to_repos`
602	///   resolves `Side::Code` to cwd's `.` when no root is given, so a
603	///   POR run still operates on the current directory.
604	pub fn default_scope(workspace_root: Option<&Path>) -> Scope {
605	    let Some(root) = workspace_root else {
606	        return Scope(vec![Side::Code]);
607	    };
608	    let cfg = match toml_simple::toml_load(&root.join(VC_CONFIG_FILE)) {
609	        Ok(c) => c,
610	        Err(_) => return Scope(vec![Side::Code]),
611	    };
612	    match toml_simple::toml_get(&cfg, "workspace.other-repo") {
613	        Some(v) if !v.is_empty() => Scope(vec![Side::Code, Side::Bot]),
614	        _ => Scope(vec![Side::Code]),
615	    }
