618	/// Resolve a `Scope` to concrete repo paths.
619	///
620	/// - `Side::Code` → `workspace_root` (or cwd's `.` when
621	///   `workspace_root` is None).
622	/// - `Side::Bot` → `workspace_root.join(other-repo)`.
623	///
624	/// Errors when `Side::Bot` is requested but the workspace doesn't
625	/// define one (POR or single-repo workspace).
626	pub fn scope_to_repos(
627	    scope: &Scope,
628	    workspace_root: Option<&Path>,
629	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
630	    let mut repos = Vec::new();
631	    for side in &scope.0 {
632	        match side {
633	            Side::Code => repos.push(
634	                workspace_root
635	                    .map(Path::to_path_buf)
636	                    .unwrap_or_else(|| PathBuf::from(".")),
637	            ),
638	            Side::Bot => {
639	                let root = workspace_root.ok_or(
640	                    "--scope=bot: not in a vc-x1 workspace (no .vc-config.toml with path = \"/\") — drop --scope or use --scope=code",
641	                )?;
642	                let cfg = toml_simple::toml_load(&root.join(VC_CONFIG_FILE))?;
643	                let other = toml_simple::toml_get(&cfg, "workspace.other-repo")
644	                    .filter(|v| !v.is_empty())
645	                    .ok_or(
646	                        "--scope=bot: no other-repo configured. Add `other-repo = \"…\"` to .vc-config.toml to enable dual-repo operations",
647	                    )?;
648	                repos.push(root.join(other));
649	            }
650	        }
651	    }
652	    Ok(repos)
653	}
