655	/// Resolve `CommonArgs.repo` + `CommonArgs.scope` into concrete repo paths.
656	///
657	/// The four `CommonArgs` consumers (`chid` / `desc` / `list` / `show`)
658	/// call this at the start of their body to translate the clap surface
659	/// into the `&[PathBuf]` that `for_each_repo` iterates. Behavior matches
660	/// today's defaults plus a composing rule for the new `--scope` flag:
661	///
662	/// - neither flag → `[.]` (today's no-arg default).
663	/// - `-R PATH` alone → `[PATH]` (today's `-R <path>` behavior;
664	///   workspace context not consulted).
665	/// - `-s ROLES` alone → resolves against `find_workspace_root()` —
666	///   the surrounding workspace if there is one, else POR
667	///   (`Side::Code` → `.`, `Side::Bot` → error).
668	/// - `-R PATH -s ROLES` → resolves with `PATH` as the workspace root
669	///   (overrides `find_workspace_root`). This is the composing case;
670	///   e.g. `chid -R ../foo -s bot` queries `../foo/.claude`.
671	///
672	/// `--scope` is keyword-only (`code|bot|code,bot|bot,code`);
673	/// path-based single-repo operation routes through `-R/--repo`.
674	pub fn resolve_repos(
675	    repo: Option<&Path>,
676	    scope: Option<&Scope>,
677	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
678	    match (repo, scope) {
679	        (None, None) => Ok(vec![PathBuf::from(".")]),
680	        (Some(p), None) => Ok(vec![p.to_path_buf()]),
681	        (Some(p), Some(s)) => scope_to_repos(s, Some(p)),
682	        (None, Some(s)) => scope_to_repos(s, find_workspace_root().as_deref()),
683	    }
684	}
