370	/// responsible for path-existence preflight.
371	fn copy_user_config(src: &Path, dir: &Path) -> Result<(), Box<dyn std::error::Error>> {
372	    std::fs::copy(src, dir.join(".vc-config.toml"))
373	        .map_err(|e| format!("--config: failed to copy {}: {e}", src.display()))?;
374	    Ok(())
375	}
